}

func isBlockedIP(ip net.IP) bool {
	for _, network := range parsedCIDRs {
		if network.Contains(ip) {
			return true
		}
	}
	return false
}

func validateURL(targetURL string) error {
	parsed, err := url.Parse(targetURL)
	if err != nil {
		return errors.New("invalid URL format")
	}

	// Only allow HTTPS
	if parsed.Scheme != "https" {
		return errors.New("only HTTPS URLs are allowed")
	}

	// Check against allowlist
	if !allowedDomains[parsed.Hostname()] {
		return errors.New("domain not in allowlist")
	}

	// Resolve DNS and check IP
	ips, err := net.LookupIP(parsed.Hostname())
	if err != nil {
		return errors.New("unable to resolve hostname")
	}

	for _, ip := range ips {
		if isBlockedIP(ip) {
			return errors.New("URL resolves to blocked IP range")
		}
	}

	return nil
}

func fetchURLSecure(w http.ResponseWriter, r *http.Request) {
	targetURL := r.URL.Query().Get("url")
	if targetURL == "" {
		http.Error(w, "URL parameter required", http.StatusBadRequest)
		return
	}

	// Validate URL before fetching
	if err := validateURL(targetURL); err != nil {
		http.Error(w, err.Error(), http.StatusForbidden)
		return
	}

	// Create client with timeout and no redirects
	client := &http.Client{
		Timeout: 10 * time.Second,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			return http.ErrUseLastResponse // Don't follow redirects
		},
	}

	resp, err := client.Get(targetURL)
	if err != nil {
		http.Error(w, "Failed to fetch URL", http.StatusInternalServerError)
		return
	}
	defer resp.Body.Close()

	// Limit response size
	limitedReader := io.LimitReader(resp.Body, 1024*1024) // 1MB max
	w.Header().Set("Content-Type", "application/octet-stream")
	io.Copy(w, limitedReader)
}

func main() {
	http.HandleFunc("/fetch", fetchURLSecure)
	http.ListenAndServe(":8080", nil)
}
