**Key Security Controls**:
- **Domain allowlisting**: Only pre-approved external domains can be accessed, blocking all internal resources
- **IP range blocking**: All private, loopback, and cloud metadata IP ranges are explicitly blocked
- **DNS resolution check**: Resolves hostnames before connecting to detect DNS rebinding attacks
- **HTTPS-only**: Prevents protocol smuggling and ensures encrypted connections
- **Redirect blocking**: Prevents attackers from using open redirects to bypass validation

Excellent question! DNS rebinding is a sophisticated attack where the attacker controls a DNS server that returns a legitimate IP during your validation check, then quickly changes to a malicious IP (like 169.254.169.254) when your application makes the actual connection. This Time-of-Check to Time-of-Use (TOCTOU) vulnerability can bypass naive IP-based protections.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/tls"
	"errors"
	"fmt"
	"io"
	"log"
	"net"
	"net/http"
	"net/url"
	"os"
	"sync"
	"time"
)

// SSRFProtector provides comprehensive SSRF protection
type SSRFProtector struct {
	allowedDomains map[string]bool
	blockedCIDRs   []*net.IPNet
	httpClient     *http.Client
	logger         *log.Logger
	mu             sync.RWMutex
}

func NewSSRFProtector(allowedDomains []string) *SSRFProtector {
	sp := &SSRFProtector{
		allowedDomains: make(map[string]bool),
		logger:         log.New(os.Stdout, "[SSRF-PROTECT] ", log.LstdFlags),
	}

	for _, domain := range allowedDomains {
		sp.allowedDomains[domain] = true
	}

	// Initialize blocked CIDR ranges
	blockedRanges := []string{
		"169.254.0.0/16",   // Link-local (cloud metadata)
		"127.0.0.0/8",      // Loopback
		"10.0.0.0/8",       // RFC1918
		"172.16.0.0/12",    // RFC1918
		"192.168.0.0/16",   // RFC1918
		"0.0.0.0/8",        // Current network
		"100.64.0.0/10",    // Carrier-grade NAT
		"192.0.0.0/24",     // IETF Protocol
		"192.0.2.0/24",     // TEST-NET-1
		"198.18.0.0/15",    // Benchmark testing
		"198.51.100.0/24",  // TEST-NET-2
		"203.0.113.0/24",   // TEST-NET-3
		"224.0.0.0/4",      // Multicast
		"240.0.0.0/4",      // Reserved
		"255.255.255.255/32", // Broadcast
		"::1/128",          // IPv6 loopback
		"fc00::/7",         // IPv6 unique local
		"fe80::/10",        // IPv6 link-local
		"::ffff:0:0/96",    // IPv4-mapped IPv6
	}

	for _, cidr := range blockedRanges {
		_, network, err := net.ParseCIDR(cidr)
		if err == nil {
			sp.blockedCIDRs = append(sp.blockedCIDRs, network)
		}
	}

	// Create custom HTTP client with SSRF-safe dialer
	sp.httpClient = sp.createSecureClient()

	return sp
}

// createSecureClient creates an HTTP client that validates IPs at connection time
func (sp *SSRFProtector) createSecureClient() *http.Client {
	// Custom dialer that validates IP at connection time (prevents DNS rebinding)
	safeDialer := &net.Dialer{
		Timeout:   5 * time.Second,
		KeepAlive: 30 * time.Second,
		Control: func(network, address string, c syscall.RawConn) error {
			// This is called right before the actual connection
			host, _, err := net.SplitHostPort(address)
			if err != nil {
				return fmt.Errorf("invalid address: %w", err)
			}

			ip := net.ParseIP(host)
			if ip == nil {
				return fmt.Errorf("invalid IP address: %s", host)
			}

			if sp.isBlockedIP(ip) {
				sp.logger.Printf("BLOCKED connection to internal IP: %s", ip)
				return fmt.Errorf("connection to internal IP blocked: %s", ip)
			}

			return nil
		},
	}

	transport := &http.Transport{
		DialContext: func(ctx context.Context, network, addr string) (net.Conn, error) {
			// Resolve DNS ourselves to validate before connecting
			host, port, err := net.SplitHostPort(addr)
			if err != nil {
				return nil, err
			}

			// Resolve with timeout
			resolver := &net.Resolver{
				PreferGo: true,
				Dial: func(ctx context.Context, network, address string) (net.Conn, error) {
					d := net.Dialer{Timeout: 2 * time.Second}
					return d.DialContext(ctx, "udp", "8.8.8.8:53") // Use trusted DNS
				},
			}

			ips, err := resolver.LookupIPAddr(ctx, host)
			if err != nil {
				return nil, fmt.Errorf("DNS resolution failed: %w", err)
			}

			if len(ips) == 0 {
				return nil, errors.New("no IP addresses found")
			}

			// Validate ALL resolved IPs
			for _, ipAddr := range ips {
				if sp.isBlockedIP(ipAddr.IP) {
					sp.logger.Printf("BLOCKED: %s resolved to internal IP %s", host, ipAddr.IP)
					return nil, fmt.Errorf("hostname resolves to blocked IP: %s", ipAddr.IP)
				}
			}

			// Connect using the first valid IP (pinned connection)
			targetAddr := net.JoinHostPort(ips[0].IP.String(), port)
			return safeDialer.DialContext(ctx, network, targetAddr)
		},
		TLSClientConfig: &tls.Config{
			MinVersion: tls.VersionTLS12,
		},
		MaxIdleConns:        100,
		IdleConnTimeout:     90 * time.Second,
		DisableCompression:  true,
		ResponseHeaderTimeout: 10 * time.Second,
	}

	return &http.Client{
		Transport: transport,
		Timeout:   30 * time.Second,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			if len(via) >= 3 {
				return errors.New("too many redirects")
			}
			// Validate redirect target
			if !sp.allowedDomains[req.URL.Hostname()] {
				sp.logger.Printf("BLOCKED redirect to non-allowlisted domain: %s", req.URL.Host)
				return fmt.Errorf("redirect to non-allowlisted domain: %s", req.URL.Host)
			}
			return nil
		},
	}
}

func (sp *SSRFProtector) isBlockedIP(ip net.IP) bool {
	for _, network := range sp.blockedCIDRs {
		if network.Contains(ip) {
			return true
		}
	}
	return false
}

// ValidateAndFetch performs comprehensive SSRF-safe URL fetching
func (sp *SSRFProtector) ValidateAndFetch(ctx context.Context, targetURL string, clientIP string) ([]byte, string, error) {
	// Parse and validate URL structure
	parsed, err := url.Parse(targetURL)
	if err != nil {
		sp.logger.Printf("INVALID URL from %s: %s", clientIP, targetURL)
		return nil, "", errors.New("invalid URL format")
	}

	// Scheme validation
	if parsed.Scheme != "https" {
		sp.logger.Printf("BLOCKED non-HTTPS request from %s: %s", clientIP, targetURL)
		return nil, "", errors.New("only HTTPS URLs are allowed")
	}

	// Domain allowlist check
	sp.mu.RLock()
	allowed := sp.allowedDomains[parsed.Hostname()]
	sp.mu.RUnlock()

	if !allowed {
		sp.logger.Printf("BLOCKED non-allowlisted domain from %s: %s", clientIP, parsed.Hostname())
		return nil, "", fmt.Errorf("domain not in allowlist: %s", parsed.Hostname())
	}

	// Block suspicious URL patterns
	if containsSuspiciousPatterns(targetURL) {
		sp.logger.Printf("BLOCKED suspicious URL pattern from %s: %s", clientIP, targetURL)
		return nil, "", errors.New("suspicious URL pattern detected")
	}

	// Create request with context
	req, err := http.NewRequestWithContext(ctx, "GET", targetURL, nil)
	if err != nil {
		return nil, "", fmt.Errorf("failed to create request: %w", err)
	}

	// Set safe headers
	req.Header.Set("User-Agent", "SecureURLFetcher/1.0")
	req.Header.Set("Accept", "*/*")

	// Execute request
	resp, err := sp.httpClient.Do(req)
	if err != nil {
		sp.logger.Printf("FETCH FAILED for %s from %s: %v", targetURL, clientIP, err)
		return nil, "", fmt.Errorf("fetch failed: %w", err)
	}
	defer resp.Body.Close()

	// Validate response status
	if resp.StatusCode < 200 || resp.StatusCode >= 400 {
		return nil, "", fmt.Errorf("upstream returned status: %d", resp.StatusCode)
	}

	// Limit response size (5MB max)
	limitedReader := io.LimitReader(resp.Body, 5*1024*1024)
	body, err := io.ReadAll(limitedReader)
	if err != nil {
		return nil, "", fmt.Errorf("failed to read response: %w", err)
	}

	sp.logger.Printf("SUCCESS: Fetched %d bytes from %s for client %s", len(body), targetURL, clientIP)

	contentType := resp.Header.Get("Content-Type")
	return body, contentType, nil
}

func containsSuspiciousPatterns(urlStr string) bool {
	suspiciousPatterns := []string{
		"169.254",
		"metadata",
		"localhost",
		"127.0.0.1",
		"0.0.0.0",
		"::1",
		"[::]",
		".internal",
		".local",
		"@", // URL authentication
		"%00", // Null byte
		"%2f", // Encoded slash
		"file://",
		"gopher://",
		"dict://",
	}

	lowerURL := strings.ToLower(urlStr)
	for _, pattern := range suspiciousPatterns {
		if strings.Contains(lowerURL, pattern) {
			return true
		}
	}
	return false
}

// HTTP Handler with rate limiting and monitoring
func (sp *SSRFProtector) FetchHandler(w http.ResponseWriter, r *http.Request) {
	ctx, cancel := context.WithTimeout(r.Context(), 30*time.Second)
	defer cancel()

	clientIP := r.RemoteAddr
	if xff := r.Header.Get("X-Forwarded-For"); xff != "" {
		clientIP = strings.Split(xff, ",")[0]
	}

	targetURL := r.URL.Query().Get("url")
	if targetURL == "" {
		http.Error(w, "URL parameter required", http.StatusBadRequest)
		return
	}

	body, contentType, err := sp.ValidateAndFetch(ctx, targetURL, clientIP)
	if err != nil {
		http.Error(w, "Request blocked or failed", http.StatusForbidden)
		return
	}

	// Set security headers
	w.Header().Set("Content-Type", contentType)
	w.Header().Set("X-Content-Type-Options", "nosniff")
	w.Header().Set("Content-Security-Policy", "default-src 'none'")
	w.Write(body)
}

