		"api.github.com",
		"cdn.example.com",
		"assets.company.com",
	}

	protector := NewSSRFProtector(allowedDomains)

	http.HandleFunc("/fetch", protector.FetchHandler)

	log.Println("Starting secure URL fetcher on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}
