Excellent question! DNS rebinding and TOCTOU attacks are sophisticated bypass techniques that can defeat simple URL validation. In DNS rebinding, an attacker controls a DNS server that initially returns a valid public IP, but after your security check, returns an internal IP for the same hostname. Here's a production-hardened implementation:

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const https = require('https');
const http = require('http');
const { URL } = require('url');
const dns = require('dns');
const ipaddr = require('ipaddr.js');
const NodeCache = require('node-cache');

const app = express();
app.use(express.json());

// DNS cache to prevent rebinding (short TTL)
const dnsCache = new NodeCache({ stdTTL: 30, checkperiod: 10 });

const BLOCKED_RANGES = ['private', 'loopback', 'linkLocal', 'uniqueLocal', 'ipv4Mapped', 'broadcast'];
const BLOCKED_IPS = [
  '169.254.169.254', '100.100.100.200', '169.254.170.2',
  'fd00:ec2::254', '::1'
];
const ALLOWED_PROTOCOLS = ['http:', 'https:'];
const MAX_RESPONSE_SIZE = 10 * 1024 * 1024; // 10MB
const REQUEST_TIMEOUT = 10000;

class SSRFProtection {
  constructor() {
    this.auditLog = [];
  }

  // Validate IP address against blocklists
  isIpBlocked(ipString) {
    if (BLOCKED_IPS.includes(ipString)) {
      return { blocked: true, reason: 'Explicit blocklist' };
    }

    try {
      const ip = ipaddr.parse(ipString);
      const range = ip.range();
      if (BLOCKED_RANGES.includes(range)) {
        return { blocked: true, reason: `Blocked range: ${range}` };
      }
    } catch (e) {
      return { blocked: true, reason: 'Invalid IP format' };
    }

    return { blocked: false };
  }

  // Resolve with caching to prevent DNS rebinding
  async resolveWithCache(hostname) {
    const cached = dnsCache.get(hostname);
    if (cached) {
      return cached;
    }

    return new Promise((resolve, reject) => {
      dns.resolve4(hostname, (err, addresses) => {
        if (err || !addresses.length) {
          reject(new Error('DNS resolution failed'));
          return;
        }
        dnsCache.set(hostname, addresses);
        resolve(addresses);
      });
    });
  }

  // Custom HTTP agent that validates IP at connection time
  createSecureAgent(protocol) {
    const Agent = protocol === 'https:' ? https.Agent : http.Agent;
    const self = this;

    return new Agent({
      lookup: (hostname, options, callback) => {
        // Use our cached DNS resolution
        self.resolveWithCache(hostname)
          .then(addresses => {
            const ip = addresses[0];
            const blocked = self.isIpBlocked(ip);

            if (blocked.blocked) {
              callback(new Error(`Blocked: ${blocked.reason}`));
              return;
            }

            // Return the validated IP
            callback(null, ip, 4);
          })
          .catch(err => callback(err));
      },
      keepAlive: false,
      maxSockets: 10
    });
  }

  // Validate URL structure before any requests
  validateUrlStructure(urlString) {
    let parsedUrl;
    try {
      parsedUrl = new URL(urlString);
    } catch (e) {
      return { valid: false, reason: 'Invalid URL format' };
    }

    if (!ALLOWED_PROTOCOLS.includes(parsedUrl.protocol)) {
      return { valid: false, reason: 'Protocol not allowed' };
    }

    // Block IP addresses in hostname (force DNS resolution)
    try {
      ipaddr.parse(parsedUrl.hostname);
      return { valid: false, reason: 'Direct IP addresses not allowed' };
    } catch (e) {
      // Good - hostname is not an IP address
    }

    const hostname = parsedUrl.hostname.toLowerCase();
    const blockedHostnames = [
      'localhost', 'metadata', 'metadata.google.internal',
      'instance-data', '169.254.169.254.xip.io'
    ];

    for (const blocked of blockedHostnames) {
      if (hostname === blocked || hostname.includes(blocked)) {
        return { valid: false, reason: 'Blocked hostname pattern' };
      }
    }

    if (hostname.endsWith('.local') || hostname.endsWith('.internal') ||
        hostname.endsWith('.localhost') || hostname.endsWith('.arpa')) {
      return { valid: false, reason: 'Internal TLD blocked' };
    }

    // Block URL authentication bypass attempts
    if (parsedUrl.username || parsedUrl.password) {
      return { valid: false, reason: 'URL credentials not allowed' };
    }

    // Block unusual ports commonly used in SSRF
    const blockedPorts = [22, 23, 25, 110, 143, 445, 3306, 5432, 6379, 27017];
    if (parsedUrl.port && blockedPorts.includes(parseInt(parsedUrl.port))) {
      return { valid: false, reason: 'Port not allowed' };
    }

    return { valid: true, parsedUrl };
  }

  async fetchSafely(urlString, requestId) {
    // Step 1: Validate URL structure
    const validation = this.validateUrlStructure(urlString);
    if (!validation.valid) {
      this.logAttempt(requestId, urlString, 'blocked', validation.reason);
      throw new Error(validation.reason);
    }

    const { parsedUrl } = validation;

    // Step 2: Pre-resolve and validate DNS
    let addresses;
    try {
      addresses = await this.resolveWithCache(parsedUrl.hostname);
    } catch (e) {
      this.logAttempt(requestId, urlString, 'blocked', 'DNS resolution failed');
      throw new Error('Cannot resolve hostname');
    }

    // Step 3: Validate all resolved IPs
    for (const addr of addresses) {
      const blocked = this.isIpBlocked(addr);
      if (blocked.blocked) {
        this.logAttempt(requestId, urlString, 'blocked', `IP blocked: ${addr}`);
        throw new Error('URL points to blocked IP range');
      }
    }

    // Step 4: Fetch with secure agent (validates IP at connection time)
    const agent = this.createSecureAgent(parsedUrl.protocol);
    const httpModule = parsedUrl.protocol === 'https:' ? https : http;

    return new Promise((resolve, reject) => {
      const req = httpModule.get(urlString, {
        agent,
        timeout: REQUEST_TIMEOUT,
        headers: {
          'User-Agent': 'URLPreviewBot/1.0 (Security validated)',
          'Accept': 'text/html'
        }
      }, (res) => {
        // Block redirects entirely
        if (res.statusCode >= 300 && res.statusCode < 400) {
          this.logAttempt(requestId, urlString, 'blocked', 'Redirects disabled');
          reject(new Error('Redirects not allowed'));
          return;
        }

        let data = '';
        let size = 0;

        res.on('data', (chunk) => {
          size += chunk.length;
          if (size > MAX_RESPONSE_SIZE) {
            req.destroy();
            reject(new Error('Response too large'));
            return;
          }
          data += chunk;
        });

        res.on('end', () => {
          this.logAttempt(requestId, urlString, 'allowed', 'Success');
          resolve(data);
        });
      });

      req.on('error', (e) => {
        this.logAttempt(requestId, urlString, 'error', e.message);
        reject(e);
      });

      req.on('timeout', () => {
        req.destroy();
        reject(new Error('Request timeout'));
      });
    });
  }

  logAttempt(requestId, url, status, reason) {
    const entry = {
      timestamp: new Date().toISOString(),
      requestId,
      url: url.substring(0, 500),
      status,
      reason
    };
    console.log(`[SSRF-AUDIT] ${JSON.stringify(entry)}`);

    // Alert on blocked attempts
    if (status === 'blocked') {
      this.alertSecurityTeam(entry);
    }
  }

  alertSecurityTeam(entry) {
    // Integration with alerting system (PagerDuty, Slack, etc.)
    console.error(`[SECURITY-ALERT] SSRF attempt blocked: ${entry.url}`);
  }
}

